import{_ as o,o as a,c,a3 as r}from"./chunks/framework.aYYe0dfI.js";const u=JSON.parse('{"title":"Module config:normalize","description":"模块 config:normalize 负责对 Clore 工具链中的配置值进行规范化处理，将其转换为标准形式以便后续验证和使用。其公开实现的核心是函数 clore::config::normalize，它接受一个 int 引用并就地更新该值，返回值通常指示操作状态；同时提供了 NormalizeError 结构体用于报告规范化过程中的错误。此外，该模块还暴露了多个公共变量，例如 workspace_root、make_absolute、normalize_separators 等，它们作为规范化过程的参数或上下文状态，共同构成模块的公开接口范围。","frontmatter":{"title":"Module config:normalize","description":"模块 config:normalize 负责对 Clore 工具链中的配置值进行规范化处理，将其转换为标准形式以便后续验证和使用。其公开实现的核心是函数 clore::config::normalize，它接受一个 int 引用并就地更新该值，返回值通常指示操作状态；同时提供了 NormalizeError 结构体用于报告规范化过程中的错误。此外，该模块还暴露了多个公共变量，例如 workspace_root、make_absolute、normalize_separators 等，它们作为规范化过程的参数或上下文状态，共同构成模块的公开接口范围。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/modules/config/normalize.md","filePath":"zh/clore/modules/config/normalize.md"}'),i={name:"zh/clore/modules/config/normalize.md"};function d(l,e,t,n,s,m){return a(),c("div",null,[...e[0]||(e[0]=[r('<h1 id="module-config-normalize" tabindex="-1">Module <code>config:normalize</code> <a class="header-anchor" href="#module-config-normalize" aria-label="Permalink to &quot;Module `config:normalize`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>模块 <code>config:normalize</code> 负责对 Clore 工具链中的配置值进行规范化处理，将其转换为标准形式以便后续验证和使用。其公开实现的核心是函数 <code>clore::config::normalize</code>，它接受一个 <code>int</code> 引用并就地更新该值，返回值通常指示操作状态；同时提供了 <code>NormalizeError</code> 结构体用于报告规范化过程中的错误。此外，该模块还暴露了多个公共变量，例如 <code>workspace_root</code>、<code>make_absolute</code>、<code>normalize_separators</code> 等，它们作为规范化过程的参数或上下文状态，共同构成模块的公开接口范围。</p><h2 id="imports" tabindex="-1">Imports <a class="header-anchor" href="#imports" aria-label="Permalink to &quot;Imports&quot;">​</a></h2><ul><li><a href="./schema"><code>config:schema</code></a></li><li><code>std</code></li></ul><h2 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types&quot;">​</a></h2><h3 id="clore-config-normalizeerror" tabindex="-1"><code>clore::config::NormalizeError</code> <a class="header-anchor" href="#clore-config-normalizeerror" aria-label="Permalink to &quot;`clore::config::NormalizeError`&quot;">​</a></h3><p>Declaration: <code>config/normalize.cppm:10</code></p><p>Definition: <code>config/normalize.cppm:10</code></p><p>Declaration: <a href="./../../namespaces/clore/config/"><code>Namespace clore::config</code></a></p><p>结构体 <code>clore::config::NormalizeError</code> 仅包含一个公开的 <code>std::string</code> 成员 <code>message</code>，其内部状态唯一地由该字符串表示。该结构体不定义构造函数、析构函数或任何成员函数，因此其不变性完全依赖于调用方正确设置 <code>message</code> 的内容——通常应是一个描述规范化失败原因的非空字符串。由于没有额外的数据成员或资源管理需求，该类型可作为轻量级错误载体，在 <code>clore::config</code> 命名空间内传递规范化操作失败时的上下文信息。</p><h4 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>The <code>message</code> field should typically be non-empty when an error is present.</li></ul><h4 id="key-members" tabindex="-1">Key Members <a class="header-anchor" href="#key-members" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>message</code>: a <code>std::string</code> describing the normalization error.</li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Returned or thrown by normalization functions to indicate failure.</li><li>Checked by callers to determine the reason for normalization failure.</li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-config-normalize" tabindex="-1"><code>clore::config::normalize</code> <a class="header-anchor" href="#clore-config-normalize" aria-label="Permalink to &quot;`clore::config::normalize`&quot;">​</a></h3><p>Declaration: <code>config/normalize.cppm:14</code></p><p>Definition: <code>config/normalize.cppm:22</code></p><p>Declaration: <a href="./../../namespaces/clore/config/"><code>Namespace clore::config</code></a></p><p>函数 <code>clore::config::normalize</code> 首先检查并设置 <code>config.workspace_root</code>：若为空，则将其赋值为 <code>std::filesystem::current_path().string()</code>。随后依次对 <code>workspace_root</code>、<code>compile_commands_path</code>、<code>project_root</code> 和 <code>output_root</code> 字段调用内部 lambda <code>make_absolute</code>。该 lambda 将空字符串视为错误并返回 <code>NormalizeError</code>；否则将路径转换为 <code>std::filesystem::path</code>，如果路径为相对形式，则基于可选的 <code>base</code> 参数（第一个调用使用 <code>std::nullopt</code>，后续调用使用已归一化的 <code>workspace_root</code> 作为基准）与 <code>p</code> 拼接或直接调用 <code>fs::absolute(p)</code>，最后通过 <code>lexically_normal().string()</code> 获取规范形式并写回原字段。若任一字段规范化失败，函数提前返回 <code>std::unexpected</code>。</p><p>在所有绝对路径处理完成后，第二个内部 lambda <code>normalize_separators</code> 将 <code>config</code> 中所有路径字段（包括 <code>compile_commands_path</code>、<code>project_root</code>、<code>output_root</code>、<code>workspace_root</code> 以及 <code>config.filter.include</code> 与 <code>config.filter.exclude</code> 列表中的每个元素）中的反斜杠 <code>\\</code> 替换为正斜杠 <code>/</code>。函数最终返回成功 <code>std::expected&lt;void, NormalizeError&gt;</code>。整个过程依赖 <code>std::filesystem</code> 的路径操作和 <code>std::format</code> 构建错误消息。</p><h4 id="side-effects" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>Mutates the <code>TaskConfig</code> struct passed by reference by modifying its path fields.</li><li>Calls <code>std::filesystem::current_path()</code> which may involve a system call to retrieve the current working directory.</li></ul><h4 id="reads-from" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>config.workspace_root</code></li><li><code>config.compile_commands_path</code></li><li><code>config.project_root</code></li><li><code>config.output_root</code></li><li><code>config.filter.include</code></li><li><code>config.filter.exclude</code></li><li><code>std::filesystem::current_path()</code></li></ul><h4 id="writes-to" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li><code>config.workspace_root</code></li><li><code>config.compile_commands_path</code></li><li><code>config.project_root</code></li><li><code>config.output_root</code></li><li><code>config.filter.include</code></li><li><code>config.filter.exclude</code></li></ul><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called before using the configuration to ensure all paths are absolute and normalized.</li><li>Used to prepare a <code>TaskConfig</code> for further processing or validation.</li></ul><h2 id="internal-structure" tabindex="-1">Internal Structure <a class="header-anchor" href="#internal-structure" aria-label="Permalink to &quot;Internal Structure&quot;">​</a></h2><p><code>config:normalize</code> 是 Clore 配置管线中的规范化模块，仅导入 <code>config:schema</code> 和 <code>std</code>。它对外暴露 <code>NormalizeError</code> 结构和 <code>normalize</code> 函数（接受 <code>int&amp;</code> 并返回 <code>int</code>，用于表示状态或结果）。内部实现按职责拆分为多个可变辅助：<code>workspace_root</code> 提供工作区根路径，<code>make_absolute</code> 处理相对路径到绝对路径的转换，<code>normalize_separators</code> 负责分隔符标准化。这些辅助变量协同完成配置值的标准化；若过程中出现错误，则通过 <code>NormalizeError::message</code> 报告失败原因。整体采用原地修改引用参数的方式，使规范化行为可组合，并保持与 <code>config:validate</code> 等后续模块的解耦。</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./schema">Module config:schema</a></li></ul>',36)])])}const h=o(i,[["render",d]]);export{u as __pageData,h as default};
